INSERT INTO destinations (name, slug, category, region, description, image_url, rating, review_count, altitude_m, difficulty, best_months, featured) VALUES
('Mohare Danda', 'mohare-danda', 'Trekking', 'Gandaki Province', 'Community eco-trek with sustainable homestays. Perfect views of Dhaulagiri and Annapurna.', 'https://images.unsplash.com/photo-1464822759023-fed622ff2cfa?w=800&q=80', 4.8, 67, 3300, 'Moderate', ARRAY['Oct', 'Nov', 'Mar', 'Apr'], true),
